import{_ as o,c as t,o as i,aN as r}from"./chunks/framework.BRm39z_l.js";const b=JSON.parse('{"title":"MySQL日志","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/04.MySQL日志.md","filePath":"mysql/04.MySQL日志.md"}'),n={name:"mysql/04.MySQL日志.md"};function g(d,l,e,a,s,u){return i(),t("div",null,l[0]||(l[0]=[r('<h1 id="mysql日志" tabindex="-1">MySQL日志 <a class="header-anchor" href="#mysql日志" aria-label="Permalink to &quot;MySQL日志&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#mysql-日志文件有哪些">MySQL 日志文件有哪些</a></li><li><a href="#介绍一下-binlog">介绍一下 binlog</a></li><li><a href="#有了-binlog-为什么还要-undolog-redolog">有了 binlog 为什么还要 undolog redolog？</a></li></ul></nav><h2 id="mysql-日志文件有哪些" tabindex="-1">MySQL 日志文件有哪些 <a class="header-anchor" href="#mysql-日志文件有哪些" aria-label="Permalink to &quot;MySQL 日志文件有哪些&quot;">​</a></h2><ul><li>慢查询日志：sql 性能分析</li><li>错误日志：问题诊断</li><li>general log：用于记录所有的 sql 语句</li><li>binlog：记录所有修改数据库状态的 SQL 语句，以及每个语句的执行时间，用于主从复制和数据恢复</li><li>redo log：保证事务持久性，记录对于 innodb 的每个写操作，用户崩溃恢复</li><li>undo log：事务回滚</li></ul><h2 id="介绍一下-binlog" tabindex="-1">介绍一下 binlog <a class="header-anchor" href="#介绍一下-binlog" aria-label="Permalink to &quot;介绍一下 binlog&quot;">​</a></h2><p>binlog 是一种二进制日志，在磁盘上记录数据库的所有修改操作</p><p>如果误删了数据，就可以使用 binlog 进行回退到误删之前的状态。</p><p>如果要搭建主从复制，就可以让从库定时读取主库的 binlog</p><p>MySQL 提供了三种格式的 binlog：Statement、Row 和 Mixed，分别对应 SQL 语句级别、行级别和混合级别，默认为行级别</p><p>从后缀名上来看，binlog 文件分为两类：以 .index 结尾的索引文件，以 .00000* 结尾的二进制日志文件</p><h2 id="有了-binlog-为什么还要-undolog-redolog" tabindex="-1">有了 binlog 为什么还要 undolog redolog？ <a class="header-anchor" href="#有了-binlog-为什么还要-undolog-redolog" aria-label="Permalink to &quot;有了 binlog 为什么还要 undolog redolog？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>日志类型</th><th>写入时间</th><th>作用</th><th>恢复能力</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>redo log</strong>（重做日志）</td><td>事务提交前（物理页刷磁盘前）</td><td>保证 <strong>事务的持久性</strong>，崩溃恢复用</td><td>crash recovery</td><td>确保提交事务在系统崩溃后不丢失</td></tr><tr><td><strong>undo log</strong>（回滚日志）</td><td>事务执行修改前</td><td>支持 <strong>事务回滚</strong> 和 <strong>MVCC 版本读取</strong></td><td>回滚或快照读</td><td>回滚事务、实现一致性读（快照隔离）</td></tr><tr><td><strong>binlog</strong>（二进制日志）</td><td>事务提交后</td><td><strong>复制/审计/备份</strong></td><td>主从同步或逻辑恢复</td><td>复制到从库、恢复历史操作、审计</td></tr></tbody></table><p>binlog 属于 Server 层，与存储引擎无关，无法直接操作物理数据页。而 redo log 和 undo log 是 InnoDB 存储引擎实现 ACID 的基石</p><p>binlog 会记录整个 SQL 或行变化；redo log 是为了恢复「已提交但未刷盘」的数据，undo log 是为了撤销未提交的事务。</p><p>以一次事务更新为例：</p><p>事务开始（START TRANSACTION）</p><ul><li>事务上下文在内存中创建</li><li>为事务分配 <strong>undo log 区域</strong></li></ul><p><strong>undo log</strong>：准备记录修改前的数据，用于回滚和快照读</p><hr><p>事务执行修改（UPDATE）</p><ol><li><strong>生成 undo log</strong><ul><li>保存修改前的旧值</li><li>支持事务回滚和 MVCC 一致性读</li></ul></li><li><strong>修改 buffer pool</strong>（内存页） <ul><li>数据页还在内存中，尚未刷盘</li></ul></li><li><strong>生成 redo log</strong>（重做日志缓冲） <ul><li>redo log 写入 <strong>重做日志缓冲区</strong></li><li>保证 crash 时可以恢复</li></ul></li></ol><hr><p>事务提交（COMMIT）</p><ol><li><strong>redo log commit</strong><ul><li>redo log 中的事务 commit 标记写入磁盘（或日志缓冲刷盘）</li><li>保证 <strong>Durability</strong>：事务提交后不会丢失</li></ul></li><li><strong>binlog 写入</strong><ul><li>binlog 是逻辑日志（记录 SQL 或行变化）</li><li>写在事务提交后，保证逻辑一致性</li><li>用于 <strong>主从复制、逻辑恢复、审计</strong></li></ul></li></ol><hr><p>数据页刷盘（Checkpoint）</p><ul><li>数据页从 <strong>buffer pool</strong> 刷到磁盘</li><li>redo log 依然保证 crash 恢复</li><li>undo log 可以保留一段时间，用于快照读</li></ul><hr><p>5️⃣ crash 恢复场景</p><ul><li><strong>事务未提交</strong>： <ul><li>redo log 没有 commit → 内存修改不持久</li><li>undo log 回滚事务 → 数据恢复到事务开始前</li><li>binlog 未写 → 不影响逻辑恢复</li></ul></li><li><strong>事务已提交</strong>： <ul><li>redo log commit → 恢复已提交修改</li><li>binlog 写入 → 主从同步/审计</li><li>undo log 可以释放或继续用于 MVCC</li></ul></li></ul>',30)]))}const p=o(n,[["render",g]]);export{b as __pageData,p as default};
